INSERT INTO knowledge_base (lang, lb_id, difficulty, page, title, tags, summary, content, eg_in, eg_out) VALUES 
('c++', 21, 'beginner', 1, '算术运算符', '["运算符","算术"]', 'C++中的基本算术运算符用于执行数学计算。', 'C++中的基本算术运算符用于执行数学计算。\\n包括加法(+)、减法(-)、乘法(*)、除法(/)、取模(%)。\\n例如，整数除法会截断小数部分，而浮点数除法保留小数。', '["int a = 10;\\nint b = 3;\\nint add = a + b;\\nint mod = a % b;", "double x = 5.0;\\ndouble y = 2.0;\\ndouble div = x / y;"]', '["add = 13, mod = 1", "div = 2.5"]'),
('c++', 22, 'beginner', 1, '赋值运算符', '["运算符","赋值"]', '赋值运算符(=)用于给变量赋值。', '赋值运算符将右侧表达式的值赋给左侧的变量。\\n例如，a = 5 将5赋给a。\\nC++还支持复合赋值运算符，如 +=、-= 等。', '["int a;\\na = 10;", "int b = 5;\\nb += 3;"]', '["a is assigned 10", "b becomes 8"]'),
('c++', 23, 'beginner', 1, '比较运算符', '["运算符","比较"]', '比较运算符用于比较两个值，返回布尔结果。', '比较运算符包括等于(==)、不等于(!=)、小于(<)、大于(>)、小于等于(<=)、大于等于(>=)。\\n它们常用于条件语句中。', '["int x = 5;\\nint y = 3;\\nbool isEqual = (x == y);", "double a = 4.5;\\ndouble b = 4.5;\\nbool isGreater = (a > b);"]', '["isEqual = false", "isGreater = false"]'),
('c++', 24, 'beginner', 1, '逻辑运算符', '["运算符","逻辑"]', '逻辑运算符用于组合布尔表达式。', '逻辑运算符包括与(&&)、或(||)、非(!)。\\n它们用于基于多个条件做出决策。', '["bool a = true;\\nbool b = false;\\nbool andResult = a && b;", "int x = 10;\\nbool cond = (x > 5) && (x < 15);"]', '["andResult = false", "cond = true"]'),
('c++', 25, 'beginner', 1, '自增自减运算符', '["运算符","自增","自减"]', '自增(++)和自减(--)运算符用于增加或减少变量的值。', '自增运算符(++)将变量的值增加1，自减运算符(--)减少1。\\n它们有前缀和后缀形式，前缀先增减后使用，后缀先使用后增减。', '["int a = 5;\\na++;\\nint b = ++a;", "int x = 10;\\nint y = x--;"]', '["a becomes 6 then 7, b = 7", "y = 10, x becomes 9"]');